SELECT id, name, email, status, department, MATCH(name, email) AGAINST(#{keyword} IN BOOLEAN MODE) as relevance FROM users
AND (MATCH(name, email) AGAINST(#{keyword} IN BOOLEAN MODE) OR name LIKE CONCAT('%', #{keyword}, '%') OR email LIKE CONCAT('%', #{keyword}, '%'))
AND status IN
#{s}
ORDER BY relevance DESC
