WITH ranked_data AS (
    SELECT
        u.id, u.name, u.department, u.salary,
        ROW_NUMBER() OVER (

                PARTITION BY department
                PARTITION BY status
                PARTITION BY department, status

            ORDER BY

                salary DESC
                name
                id

        ) as rn,
        COUNT(*) OVER (
            PARTITION BY ${partitionBy}
            PARTITION BY department
        ) as partition_cnt,
        SUM(salary) OVER (
            PARTITION BY ${partitionBy}
            PARTITION BY department
            ORDER BY id
            ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
        ) as running_sum
    FROM users u


            AND u.status = #{status}


            AND u.department_id IN

                #{did}



)
SELECT * FROM ranked_data

    WHERE rn >= #{minRank}


    AND rn <= #{maxRank}

WITH
active_orders AS (
    SELECT o.id, o.user_id, o.amount, o.created_at
    FROM orders o


            o.status IN

                #{s}



            AND o.amount >= #{minAmount}


),
user_summary AS (
    SELECT u.id, u.name, COUNT(o.id) as order_count, SUM(o.amount) as total_amount
    FROM users u
    LEFT JOIN active_orders o ON u.id = o.user_id

        WHERE u.department = #{deptFilter}

    GROUP BY u.id, u.name
),
top_users AS (
    SELECT * FROM user_summary

        WHERE order_count >= #{minOrders}

    ORDER BY total_amount DESC

        LIMIT #{limit}

)
SELECT tu.*, ou.id as latest_order_id, ou.amount as latest_order_amount
FROM top_users tu
LEFT JOIN (
    SELECT o.user_id, o.id, o.amount,
           ROW_NUMBER() OVER (PARTITION BY o.user_id ORDER BY o.created_at DESC) as rn
    FROM orders o
) ou ON tu.id = ou.user_id AND ou.rn = 1

SELECT *
FROM users u
WHERE u.id IN (
    SELECT o.user_id FROM orders o
    WHERE o.id IN (
        SELECT op.order_id FROM order_products op
        WHERE op.product_id IN



                    #{pid}


            SELECT id FROM products WHERE category = #{category}


            AND op.quantity >= #{minQuantity}

    )

        GROUP BY o.user_id HAVING SUM(o.amount) >= #{minOrderAmount}

)

    AND u.status = #{userStatus}


    ORDER BY ${sortField}

SELECT id, name, department, salary, CASE
WHEN salary >= #{highSalary} THEN 'VIP' WHEN salary >= #{midSalary} THEN 'Regular' ELSE 'Basic'
WHEN department = 'Sales' THEN 'SalesTeam' WHEN department = 'Tech' THEN 'TechTeam' WHEN department = 'HR' THEN 'HRTeam' ELSE 'Other'
WHEN status = 'active' AND department = 'Tech' THEN 'ActiveTech' WHEN status = 'active' THEN 'ActiveOther' ELSE 'Inactive'
END as tier, CASE WHEN salary >= (SELECT AVG(salary) FROM users WHERE department = u.department) THEN 'AboveAvg' ELSE 'BelowAvg' END as salary_comparison, CASE
WHEN ${rule.condition} THEN #{rule.result}
ELSE 'default' END as custom_tier FROM users u
AND u.status IN
#{s}
ORDER BY ${sortBy}

