WITH base_data AS ( SELECT u.id as user_id, u.name as user_name, u.department, o.id as order_id, o.amount, o.status as order_status, o.created_at, p.id as product_id, p.name as product_name, p.category, c.id as category_id, c.name as category_name, ROW_NUMBER() OVER (
PARTITION BY u.id ORDER BY o.amount DESC PARTITION BY u.id ORDER BY o.created_at DESC PARTITION BY u.id ORDER BY o.id
) as order_rank, COUNT(*) OVER (PARTITION BY u.id) as user_order_count, SUM(o.amount) OVER (PARTITION BY u.id) as user_total_amount, AVG(o.amount) OVER (PARTITION BY u.id) as user_avg_amount FROM users u LEFT JOIN orders o ON u.id = o.user_id LEFT JOIN order_products op ON o.id = op.order_id LEFT JOIN products p ON op.product_id = p.id LEFT JOIN categories c ON p.category_id = c.id
AND o.created_at >= #{startDate}
AND o.created_at <= #{endDate}
AND u.status = #{userStatus}
AND o.status IN
#{os}
AND c.id IN
#{cid}
), summary AS ( SELECT department, COUNT(DISTINCT user_id) as user_count, SUM(amount) as total_amount, AVG(amount) as avg_amount, MAX(amount) as max_amount, MIN(amount) as min_amount, COUNT(order_id) as order_count, COUNT(DISTINCT category_id) as category_count FROM base_data GROUP BY department ), ranked AS ( SELECT bd.*, RANK() OVER (ORDER BY bd.user_total_amount DESC) as amount_rank, DENSE_RANK() OVER (ORDER BY bd.user_order_count DESC) as frequency_rank FROM base_data bd WHERE bd.order_rank = 1 ) SELECT r.user_id, r.user_name, r.department, r.user_order_count, r.user_total_amount, r.user_avg_amount, r.amount_rank, r.frequency_rank, s.total_amount as dept_total, s.avg_amount as dept_avg, s.category_count FROM ranked r JOIN summary s ON r.department = s.department
WHERE r.user_order_count >= #{minOrderCount}
AND r.department = #{deptFilter}
ORDER BY r.user_total_amount DESC
ORDER BY r.user_order_count DESC
ORDER BY r.user_id
LIMIT #{limit}

